#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;

vec2 uv1 = (vUv-.5);
vec2 uv6 = uv1;

float rota = lum(texture(sampler_noise_hq,vUv/4))*q31;

uv6 = multiply(uv1,mat2(cos(rota),-sin(rota),sin(rota),cos(rota)));
uv6 += sin(q32*uv1);
mus = .2/(sqrt(uv6.x)+.2);

mus *= vec3 (1.1,1,.95);
mus *= .9+.1*texture(sampler_noise_hq,vUv);

vec3 blur = GetBlur1(fract(vUv));

vec2 hor = vec2 (0.005,0);
vec2 ver = vec2 (0,.005);

float dx = lum(texture(sampler_main,vUv+hor)
         - texture(sampler_main,vUv-hor));
float dy = lum(texture(sampler_main,vUv+ver)
         - texture(sampler_main,vUv-ver));


vec2 zz = vec2 (dx,dy);

vec3 crisp= texture(sampler_main,vUv+zz*.02);
vec3 crisp2 = texture(sampler_main,vUv);
crisp += crisp2/2;
crisp *= .67;
crisp +=.08 * mus - length(zz)*blur;

vec3 ret1 = crisp - lum(blur)*.04;
ret = ret1 * .99 -  .04 ;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//vUv = uv_lens_half_sphere(vUv, vec2(0.6,0.7), 0.15, 2);
vUv = uv_lens_half_sphere(vUv, 0.5, 0.45, 0.5+audioLowSmooth*0.05);
float t = uTime*0.04; // set velocity here
vec2 c = (vUv-0.5)*uAspect.wz;
float1 ang_hq = atan(c.x,c.y);
vec2 spiral = vec2(-ang_hq*M_INV_PI_2*2-t,uAspect.w*log(length(c))*(.5+audioHighSmooth*0.015)+ang_hq*M_INV_PI_2*2-t*8);
vec2 mirror = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 )); // mirror
vUv = mirror;

vUv -= 0.5;
vUv *= uAspect.xy;
vec2 hor = vec2 (0.004,0);
vec2 ver = vec2 (0,.004);

ret1 = 0; anz = 3;
float t_rel = q29;


for (n=1;n<=anz;n++) {
    m =  n-int(t_rel);

    dist = 1-fract(n/anz-fract(-t_rel)/anz);
    zoom = 2 ;
    dist2 = dist*dist;
    inten =  pow(dist,.3)*(1-dist2);

    uv2 =zoom*dist*(vUv -.4)-.1; //Blickpunkt vert.
    uv3 = fract(uv2+(m+q28)*vec2(.4,1));

    dx = lum(GetPixel(uv3+hor)
        - GetPixel(uv3-hor));
    dy = lum(GetPixel(uv3+ver)
         - GetPixel(uv3-ver));

    zz = vec2 (dx,dy);
    neu = GetPixel (uv3+.5*zz);
    glow = GetBlur1(uv3) * vec3 (.5,1,1);

    mask = 1-clamp01(8*neu);
    ret1 = ret1*mask + (neu+2*glow)*inten;
//n++;
}

uv1 = vUv + vec2(2*fract(.003*uTime)-.55,.25) - ret1/8;
float moon = clamp01(.01/length(uv1));


float mask = clamp01(1-2*ret1.r);
sky = .4*clamp01(.4-vUv.y) * vec3 (.2,0.3,1);
ret = ret1*vec3(0,1,1)+ sky*mask;
ret = ret + 8*ret*moon;

//ret = GetPixel(vUv+.5)*2;

  fragColor = ret;
}
